#include <stdio.h>
#include <stdlib.h>

int main(){
    int N, Q;
    if(scanf("%d %d", &N, &Q)!=2) return 0;
    int *arr = (int*)malloc(N * sizeof(int));
    for(int i=0;i<N;i++) scanf("%d", &arr[i]);
    int size = N;
    for(int qi=0; qi<Q; ++qi){
        int type; scanf("%d", &type);
        if(type==0){
            int pos; scanf("%d", &pos);
            // shift left from pos-1
            for(int i=pos-1;i<size-1;i++) arr[i]=arr[i+1];
            size--;
        }else{ // type == 1
            int pos, val; scanf("%d %d", &pos, &val);
            arr = (int*)realloc(arr, (size+1)*sizeof(int));
            for(int i=size;i>pos-1;--i) arr[i]=arr[i-1];
            arr[pos-1]=val;
            size++;
        }
        if(size==0){
            printf("\n");
        }else{
            for(int i=0;i<size;i++){
                if(i) printf(" ");
                printf("%d", arr[i]);
            }
            printf("\n");
        }
    }
    free(arr);
    return 0;
}

