#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N,Q;
    if(!(cin>>N>>Q)) return 0;
    vector<int> lst(N);
    for(int &x: lst) cin>>x;
    for(int i=0;i<Q;++i){
        int type; cin>>type;
        if(type==0){
            int pos; cin>>pos;
            lst.erase(lst.begin()+pos-1);
        }else{ // type==1
            int pos,val; cin>>pos>>val;
            lst.insert(lst.begin()+pos-1, val);
        }
        if(lst.empty()) cout<<"\n";
        else{
            for(size_t j=0;j<lst.size();++j){
                if(j) cout<<' ';
                cout<<lst[j];
            }
            cout<<"\n";
        }
    }
    return 0;
}

